<template>
	<view class="jasper__box" :style="{'align-items':textAlign}">
		<text class="jasper__base" :class="['jasper-t'+type, fontClass]" :style="{'color':color}">{{title}}</text>
	</view>
</template>

<script>
	/**
	 * Title 章节标题
	 * @description 章节标题，通常用于记录页面标题，使用当前组件，jasper-app 如果开启统计，将会自动统计页面标题
	 * @tutorial 仿uni-ttile 二次开发  官网：https://ext.dcloud.net.cn/plugin?id=1066
	 * @property {String} type = [h1|h2|h3|h4|h5] 标题类型
	 * 	@value h1 一级标题
	 * 	@value h2 二级标题
	 * 	@value h3 三级标题
	 * 	@value h4 四级标题
	 * 	@value h5 五级标题
	 * @property {String} title 章节标题内容
	 * @property {String} align = [left|center|right] 对齐方式
	 * 	@value left 左对齐
	 * 	@value center 居中对齐
	 * 	@value right 右对齐
	 * @property {String} color 字体颜色
	 * @property {Boolean} stat = [true|false] 是否开启统计功能呢，如不填写type值，默认为开启，填写 type 属性，默认为关闭
	 * @property {String} src 自定义字体http或https url eg:https://at.alicdn.com/t/webfont_cmet1sx1z5a.ttf
	 * @property {Boolean} useCustomFont 是否使用自定义字体 默认 不使用 false
	 */
	export default {
		name:"jasper-title",
		props: {
			type: {
				type: String,
				default: ''
			},
			title: {
				type: [String, Number],
				default: ''
			},
			align: {
				type: String,
				default: 'left'
			},
			color: {
				type: String,
				default: '#333333'
			},
			stat: {
				type: [Boolean, String],
				default: ''
			},
			useCustomFont:{
				type: Boolean,
				default: false
			},
			src:{
				type: String,
				default: null
			},
		},
		created() {
			// #ifdef APP-NVUE
			//nvue使用自定义字体
			const domModule = uni.requireNativePlugin('dom')
			if(this.src){
				domModule.addRule('fontFace', {
					'fontFamily': "customFamily",
					'src': "url('" + this.src + "')",
				});
			}else{
				domModule.addRule('fontFace', {
					'fontFamily': "customFamily",
					//默认 思源宋体bold 使用后端服务接口生成
					'src': "url('data:font/truetype;charset=utf-8;base64,')",
				});
			}			
			// #endif
		},
		data() {
			return {
			};
		},
		computed: {
			fontClass(){
				// #ifdef APP-NVUE
				//nvue style 不支持css引入
				return this.useCustomFont ? 'custom-font': '';
				// #endif
				// #ifndef APP-NVUE
				//除了nvue 都支持style引入 该样式在全局 `app-custom-font` 中来替换
				return this.useCustomFont ? 'app-custom-font': '';
				// #endif
			},
			textAlign() {
				let align = 'center';
				switch (this.align) {
					case 'left':
						align = 'flex-start'
						break;
					case 'center':
						align = 'center'
						break;
					case 'right':
						align = 'flex-end'
						break;
				}
				return align
			}
		},
		watch: {
			title(newVal) {
				// do something...
			}
		},
		mounted() {
		},
		methods: {
		}
	}
</script>

<style>

	.jasper__box {
		/* #ifndef APP-NVUE */
		display: flex;
		/* #endif */
		flex-direction: column;
		align-items: flex-start;
		justify-content: center;
		padding: 8px 0;
		flex: 1;
	}

	.jasper__base {
		font-size: 15px;
		color: #333;
		font-weight: 500;
	}
	.custom-font{
		font-family: customFamily;
	}
	.jasper-th1 {
		font-size: 20px;
		color: #333;
		font-weight: bold;
	}

	.jasper-th2 {
		font-size: 18px;
		color: #333;
		font-weight: bold;
	}

	.jasper-th3 {
		font-size: 16px;
		color: #333;
		font-weight: bold;
	}

	.jasper-th4 {
		font-size: 14px;
		color: #333;
		font-weight: bold;
	}

	.jasper-th5 {
		font-size: 12px;
		color: #333;
		font-weight: bold;
	}
</style>
